parameters.jsCode:
// Parse and validate the incoming property payload
const body = $input.first().json.body || $input.first().json;

if (!body.id || !body.zona) {
  throw new Error('Property payload missing id or zona');
}

const formatEur = (n) => {
  if (!n) return 'Contacte-nos';
  if (n >= 1000000) return `€${(n/1000000).toFixed(1)}M`;
  if (n >= 1000) return `€${Math.round(n/1000)}K`;
  return `€${n}`;
};

return [{
  json: {
    property_id: body.id,
    zona: body.zona,
    tipo: body.tipo || 'Todos',
    preco: body.preco || 0,
    nome: body.nome || 'Novo Imóvel',
    quartos: body.quartos || 0,
    area: body.area || 0,
    badge: body.badge || null,
    preco_formatted: formatEur(body.preco),
    url: `https://www.agencygroup.pt/imoveis/${body.id}`,
    criteria: {
      zona: body.zona,
      tipo: body.tipo || 'Todos',
      preco: body.preco || 0,
      quartos: body.quartos || 0,
      piscina: body.piscina || false,
    }
  }
}];

// Filter subscribers who match this property
const subs = $input.first().json.subscriptions || [];
const property = $node['Code — Parse Property'].json;

const matched = subs.filter(sub => {
  // Zone match (Todas = all zones)
  const zonaOk = sub.zona === 'Todas' || sub.zona === property.zona;
  // Type match
  const tipoOk = sub.tipo === 'Todos' || sub.tipo === property.tipo;
  // Price match
  const precoOk = !sub.preco_max || property.preco <= sub.preco_max;
  // Bedrooms match
  const quartosOk = !sub.quartos_min || property.quartos >= sub.quartos_min;
  // Pool
  const piscinaOk = !sub.piscina || property.piscina === true;
  return zonaOk && tipoOk && precoOk && quartosOk && piscinaOk;
});

console.log(`[property-match] ${matched.length} subscribers match property ${property.property_id} in ${property.zona}`);

if (matched.length === 0) {
  return [{ json: { matched: [], count: 0, property } }];
}

// Return one item per subscriber for the email loop
return matched.map(sub => ({
  json: {
    ...property,
    subscriber_email: sub.email,
    subscriber_id: sub.id,
    subscriber_zona: sub.zona,
    subscriber_tipo: sub.tipo,
    unsubscribe_url: `https://www.agencygroup.pt/api/alerts/unsubscribe?email=${encodeURIComponent(sub.email)}&zona=${encodeURIComponent(sub.zona)}&tipo=${encodeURIComponent(sub.tipo)}`,
  }
}));

